51	import type { ChangeEvent, ReadOnlyBook } from '@shardworks/stacks-apparatus';
52	import type { WritDoc, WritPhase } from '@shardworks/clerk-apparatus';
53	
54	import type { ClockworksApi } from './types.ts';
55	
56	// ── Constants ────────────────────────────────────────────────────────
57	
58	/** Plugin id used as the literal `emitter` value on every framework event. */
59	const FRAMEWORK_EMITTER = 'framework';
60	
61	/**
62	 * Map a writ target phase to the writ-lifecycle suffix from the catalog.
63	 *
64	 * Returns null for phases that are not part of the catalog
65	 * (`new`, `cancelled`).
66	 */
67	function lifecycleSuffix(phase: WritPhase): string | null {
68	  switch (phase) {
69	    case 'open':
70	      return 'ready';
71	    case 'stuck':
72	      return 'stuck';
73	    case 'completed':
74	      return 'completed';
75	    case 'failed':
76	      return 'failed';
77	    case 'new':
78	    case 'cancelled':
79	      return null;
80	  }
81	}
82	
83	/**
84	 * Walk `parentId` to the root and return the root writ's id. For a writ
85	 * with no parent, returns its own id. Bounded by the depth of the tree
86	 * — Clerk's parentId-immutability invariant is assumed; no cycle guard
87	 * is needed.
88	 *
89	 * Reads tolerate the parent disappearing mid-walk (a rare race against
90	 * deletion) by stopping at the last reachable ancestor and returning
91	 * its id.
92	 */
93	async function deriveCommissionId(
94	  writsBook: ReadOnlyBook<WritDoc>,
95	  writ: WritDoc,
96	): Promise<string> {
97	  let current: WritDoc = writ;
98	  while (current.parentId) {
99	    const parent = await writsBook.get(current.parentId);
100	    if (!parent) return current.id;
101	    current = parent;
102	  }
103	  return current.id;
104	}
105	
106	/** A root mandate is the entry point for the `commission.*` namespace. */
107	function isRootMandate(writ: WritDoc): boolean {
108	  return writ.type === 'mandate' && !writ.parentId;
109	}
