120	 * with a `console.warn` breadcrumb. Decision D13: an emission failure
121	 * must never propagate back to the originating writ transition.
122	 */
123	async function safeEmit(
124	  clockworks: ClockworksApi,
125	  name: string,
126	  payload: unknown,
127	): Promise<void> {
128	  try {
129	    await clockworks.emit(name, payload, FRAMEWORK_EMITTER);
130	  } catch (err) {
131	    const reason = err instanceof Error ? err.message : String(err);
