154	  // patches (title rename, codex inheritance, etc.) must not produce
155	  // lifecycle events. For create events the "delta" is the writ entering
156	  // existence at its initial phase.
157	  if (event.type === 'update') {
158	    if (writ.phase === event.prev.phase) return;
159	  }
160	
161	  const suffix = lifecycleSuffix(writ.phase);
162	  if (suffix === null) {
163	    // No catalog entry for this phase — `new` (drafts) and `cancelled`
164	    // are silent per D3 / D17.
165	    return;
166	  }
167	
168	  // Derive commissionId by walking parentId. Done once per fire and
169	  // shared between writ-lifecycle and commission emissions.
170	  let commissionId: string;
171	  try {
172	    commissionId = await deriveCommissionId(deps.writsBook, writ);
173	  } catch (err) {
174	    // A writs-book read failure is unexpected at this layer; degrade by
175	    // tagging the writ's own id and continuing — emission must remain
176	    // best-effort per D13.
177	    const reason = err instanceof Error ? err.message : String(err);
178	    console.warn(
179	      `[clockworks] failed to derive commissionId for writ "${writ.id}": ${reason}`,
180	    );
181	    commissionId = writ.id;
182	  }
183	
184	  // ── Writ-lifecycle event ───────────────────────────────────────────
185	  const lifecycleName = `${writ.type}.${suffix}`;
186	  await safeEmit(deps.clockworks, lifecycleName, {
187	    writId: writ.id,
188	    writType: writ.type,
189	    phase: writ.phase,
190	    commissionId,
191	    title: writ.title,
192	    ...(writ.parentId !== undefined ? { parentId: writ.parentId } : {}),
193	  });
194	
195	  // ── Commission events (root mandates only — D5/D15/D19) ───────────
196	  if (!isRootMandate(writ)) return;
197	
198	  const commissionPayloadBase = {
199	    commissionId: writ.id,
200	    writId: writ.id,
201	    phase: writ.phase,
202	    title: writ.title,
203	  };
204	
205	  // `commission.posted` fires every time a root mandate enters `open`
206	  // (D15) — direct creation in open OR new → open via writ-publish OR
207	  // stuck → open re-entry. The catalog uses "posted" to mean "in the
208	  // queue", which is exactly the meaning of phase entry into `open`.
209	  if (writ.phase === 'open') {
210	    await safeEmit(deps.clockworks, 'commission.posted', commissionPayloadBase);
211	  }
212	
213	  // Every phase change on a root mandate fires a `state.changed` event.
214	  // For `create` events this is the initial phase entry; for `update`
215	  // events the phase delta was already gated above.
216	  await safeEmit(deps.clockworks, 'commission.state.changed', {
217	    ...commissionPayloadBase,
218	    ...(event.type === 'update' ? { previousPhase: event.prev.phase } : {}),
219	  });
220	
221	  // Both `commission.sealed` AND `commission.completed` fire on entry
222	  // into `completed` (D5). Documenting the sealed/completed duplicate
223	  // is a follow-up observation; this commission ships both as the
224	  // catalog enumerates them.
225	  if (writ.phase === 'completed') {
226	    await safeEmit(deps.clockworks, 'commission.sealed', commissionPayloadBase);
227	    await safeEmit(deps.clockworks, 'commission.completed', commissionPayloadBase);
228	  }
229	
230	  if (writ.phase === 'failed') {
231	    await safeEmit(deps.clockworks, 'commission.failed', {
232	      ...commissionPayloadBase,
233	      ...(typeof writ.resolution === 'string' ? { resolution: writ.resolution } : {}),
234	    });
235	  }
236	}
