204	  });
205	
206	  const now = Date.now();
207	  let recovered = 0;
208	
209	  for (const doc of activeSessions) {
210	    // Legacy record without lastActivityAt — backfill via the reducer's
211	    // heartbeat-touch variant (D17). The doc is already in hand from
212	    // the find() iteration, so the read+reduce+put is one round-trip.
213	    if (!doc.lastActivityAt) {
214	      try {
215	        const touched = reduceSessionTransition(doc, {
216	          kind: 'heartbeat-touch',
217	          id: doc.id,
218	          lastActivityAt: new Date().toISOString(),
219	        });
220	        await sessions.put(touched);
221	        console.log(`[animator] Backfilled lastActivityAt for legacy session ${doc.id}`);
222	      } catch (err) {
223	        console.warn(
224	          `[animator] Failed to backfill lastActivityAt for ${doc.id}: ${err instanceof Error ? err.message : err}`,
225	        );
226	      }
227	      continue;
228	    }
