231	    const effectiveSilence = silence - downtimeCreditMs;
232	
233	    if (effectiveSilence <= STALENESS_THRESHOLD_MS) {
234	      continue;
235	    }
236	
237	    // Session is stale — mark as failed via the reducer's orphan-failed
238	    // variant (lastActivityAt is intentionally NOT refreshed: the host
239	    // is presumed dead, so the existing field tells the truth).
240	    const endedAt = new Date().toISOString();
241	    const durationMs = new Date(endedAt).getTime() - new Date(doc.startedAt).getTime();
242	    const updated = reduceSessionTransition(doc, {
243	      kind: 'orphan-failed',
244	      id: doc.id,
245	      endedAt,
246	      durationMs,
247	      exitCode: 1,
248	      error: `No heartbeat received for ${Math.round(effectiveSilence / 1000)}s — session host presumed dead (reconciled)`,
249	    });
